import React, { useState, useEffect } from 'react';
import { Subject, Question } from '../types';

interface CBTEngineProps {
  subject: Subject;
  onExit: () => void;
}

const CBTEngine: React.FC<CBTEngineProps> = ({ subject, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [timeLeft, setTimeLeft] = useState(600); // 10 minutes
  const [isFinished, setIsFinished] = useState(false);

  useEffect(() => {
    if (timeLeft <= 0) {
      setIsFinished(true);
      return;
    }
    const timer = setInterval(() => setTimeLeft((prev) => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft]);

  const currentQuestion = subject.questions[currentIndex];

  const handleSelectOption = (optionIndex: number) => {
    setAnswers({ ...answers, [currentQuestion.id]: optionIndex });
  };

  const calculateScore = () => {
    let score = 0;
    subject.questions.forEach((q) => {
      if (answers[q.id] === q.correctAnswer) {
        score++;
      }
    });
    return score;
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (isFinished) {
    const score = calculateScore();
    const percentage = Math.round((score / subject.questions.length) * 100);

    return (
      <div className="max-w-2xl mx-auto p-8 glass-effect rounded-2xl shadow-xl text-center">
        <h2 className="text-3xl font-bold text-slate-900 mb-4">Exam Completed!</h2>
        <div className="text-6xl font-bold text-amber-600 mb-6">{percentage}%</div>
        <p className="text-slate-600 mb-8">
          You answered {score} out of {subject.questions.length} questions correctly.
        </p>
        <div className="space-y-4">
          <button
            onClick={() => {
                setCurrentIndex(0);
                setAnswers({});
                setTimeLeft(600);
                setIsFinished(false);
            }}
            className="w-full py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700"
          >
            Try Again
          </button>
          <button
            onClick={onExit}
            className="w-full py-3 border border-slate-200 text-slate-600 rounded-xl font-bold hover:bg-slate-50"
          >
            Back to Portal
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">{subject.name}</h2>
          <p className="text-slate-500">{subject.level} Assessment</p>
        </div>
        <div className="px-4 py-2 bg-slate-900 text-white rounded-full font-mono font-bold">
          {formatTime(timeLeft)}
        </div>
      </div>

      <div className="mb-4 flex gap-1">
        {subject.questions.map((_, i) => (
          <div
            key={i}
            className={`h-2 flex-1 rounded-full ${
              i === currentIndex ? 'bg-amber-600' : answers[subject.questions[i].id] !== undefined ? 'bg-green-400' : 'bg-slate-200'
            }`}
          />
        ))}
      </div>

      <div className="glass-effect rounded-2xl p-8 shadow-sm border mb-8 min-h-[400px]">
        <span className="text-amber-600 font-bold mb-2 block">Question {currentIndex + 1} of {subject.questions.length}</span>
        <h3 className="text-xl sm:text-2xl font-semibold text-slate-900 mb-8">{currentQuestion.text}</h3>

        <div className="space-y-4">
          {currentQuestion.options.map((option, idx) => (
            <button
              key={idx}
              onClick={() => handleSelectOption(idx)}
              className={`w-full text-left p-4 rounded-xl border-2 transition-all ${
                answers[currentQuestion.id] === idx
                  ? 'border-amber-600 bg-amber-50 text-amber-900'
                  : 'border-slate-100 hover:border-slate-200 text-slate-700'
              }`}
            >
              <div className="flex items-center">
                <span className="w-8 h-8 rounded-full bg-white border flex items-center justify-center mr-3 font-bold">
                  {String.fromCharCode(65 + idx)}
                </span>
                {option}
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="flex justify-between">
        <button
          disabled={currentIndex === 0}
          onClick={() => setCurrentIndex(currentIndex - 1)}
          className="px-6 py-3 border rounded-xl font-bold disabled:opacity-30"
        >
          Previous
        </button>

        {currentIndex === subject.questions.length - 1 ? (
          <button
            onClick={() => setIsFinished(true)}
            className="px-8 py-3 bg-green-600 text-white rounded-xl font-bold hover:bg-green-700 shadow-lg"
          >
            Submit Exam
          </button>
        ) : (
          <button
            onClick={() => setCurrentIndex(currentIndex + 1)}
            className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 shadow-lg"
          >
            Next Question
          </button>
        )}
      </div>
    </div>
  );
};

export default CBTEngine;

import React, { useState, useRef, useEffect } from 'react';
import { gemini } from '../services/geminiService';
import { Message, SchoolLevel } from '../types';

const AIAssistant: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', content: "Hello! I'm Christaville's AI Tutor. I can help you with your subjects, explain tricky topics, or even practice questions with you. What would you like to learn today?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [level, setLevel] = useState<SchoolLevel>(SchoolLevel.GRADE);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await gemini.chat([...messages, userMsg], level);
      setMessages(prev => [...prev, { role: 'model', content: response }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', content: "Sorry, I had a momentary glitch. Could you try asking that again?" }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[70vh] glass-effect rounded-2xl shadow-xl overflow-hidden border">
      <div className="bg-slate-900 p-4 text-white flex justify-between items-center">
        <div className="flex items-center">
          <div className="w-8 h-8 bg-amber-500 rounded-full mr-3 animate-pulse"></div>
          <div>
            <h3 className="font-bold">Christaville AI Tutor</h3>
            <p className="text-xs text-slate-400">Online & Ready to Help</p>
          </div>
        </div>
        <select 
          value={level}
          onChange={(e) => setLevel(e.target.value as SchoolLevel)}
          className="bg-slate-800 text-xs border-none rounded px-2 py-1 text-white outline-none"
        >
          <option value={SchoolLevel.NURSERY}>Nursery Level</option>
          <option value={SchoolLevel.GRADE}>Grade Level</option>
          <option value={SchoolLevel.JUNIOR_SECONDARY}>Junior Secondary</option>
        </select>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-4 rounded-2xl ${
              msg.role === 'user' 
                ? 'bg-amber-600 text-white rounded-tr-none' 
                : 'bg-slate-100 text-slate-800 rounded-tl-none'
            }`}>
              <p className="whitespace-pre-wrap leading-relaxed">{msg.content}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-100 p-4 rounded-2xl rounded-tl-none flex space-x-1">
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={chatEndRef} />
      </div>

      <div className="p-4 bg-white border-t flex gap-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Ask me anything about your lessons..."
          className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-amber-500"
        />
        <button
          onClick={handleSend}
          disabled={isLoading}
          className="bg-slate-900 text-white px-6 py-3 rounded-xl hover:bg-slate-800 transition-colors disabled:opacity-50"
        >
          Send
        </button>
      </div>
    </div>
  );
};

export default AIAssistant;

