import { SchoolLevel, Subject, Question, SchoolConfig } from './types';

// Helper to generate 50 questions for a subject if they aren't provided
const ensure50Questions = (subjectName: string, level: SchoolLevel, seedQuestions: Question[]): Question[] => {
  const result = [...seedQuestions];
  const topics: Record<string, string[]> = {
    'Literacy': ['letter', 'alphabet', 'vowel', 'consonant', 'sound'],
    'Numbers & Shapes': ['number', 'counting', 'triangle', 'circle', 'square'],
    'General Science': ['planet', 'energy', 'matter', 'ecosystem', 'biology'],
    'English Grammar': ['noun', 'verb', 'adjective', 'pronoun', 'preposition'],
    'Algebra & Logic': ['equation', 'variable', 'set', 'logic', 'math'],
    'Basic Technology': ['tool', 'machine', 'drawing', 'material', 'safety']
  };

  const currentTopics = topics[subjectName] || ['lesson', 'topic', 'subject'];

  for (let i = seedQuestions.length + 1; i <= 50; i++) {
    const topic = currentTopics[i % currentTopics.length];
    result.push({
      id: `${subjectName.toLowerCase().replace(/\s/g, '-')}-${i}`,
      text: `Practice Question #${i}: Which of the following best describes the fundamental concept of ${topic} in ${level} level studies?`,
      options: [
        `Option A: Core ${topic} principle`,
        `Option B: Secondary ${topic} application`,
        `Option C: Advanced ${level} theoretical approach`,
        `Option D: None of the above`
      ],
      correctAnswer: i % 4
    });
  }
  return result;
};

