import React, { useState, useEffect } from 'react';
import { UserRole, User } from '../types';

interface LoginPageProps {
  onLogin: (user: User) => void;
  initialMode?: 'login' | 'register';
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin, initialMode = 'login' }) => {
  const [isLoginView, setIsLoginView] = useState(initialMode === 'login');
  const [role, setRole] = useState<UserRole>(UserRole.STUDENT);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');

  // Update view mode if initialMode prop changes
  useEffect(() => {
    setIsLoginView(initialMode === 'login');
  }, [initialMode]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (isLoginView) {
      // Specific Admin Check
      if (username === 'sabatex1979' && password === '1234_ABCsadiku') {
        onLogin({ username, role: UserRole.ADMIN, fullName: 'System Administrator' });
        return;
      }

      if (username && password) {
        onLogin({ 
          username, 
          role, 
          fullName: username.charAt(0).toUpperCase() + username.slice(1) 
        });
      } else {
        setError('Please provide both username and password.');
      }
    } else {
      // Register logic (mock)
      if (username && password && fullName) {
        onLogin({ username, role, fullName });
      } else {
        setError('Please fill in all fields.');
      }
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 pt-16">
      <div className="max-w-md w-full glass-effect p-8 rounded-3xl shadow-xl border">
