const ensure50Questions = (subjectName: string, level: SchoolLevel, seedQuestions: Question[]): Question[] => {
  const result = [...seedQuestions];
  const topics: Record<string, string[]> = {
    'Literacy': ['letter', 'alphabet', 'vowel', 'consonant', 'sound'],
    'Numbers & Shapes': ['number', 'counting', 'triangle', 'circle', 'square'],
    'General Science': ['planet', 'energy', 'matter', 'ecosystem', 'biology'],
    'Mathematics': ['calculus', 'geometry', 'statistics', 'logic', 'algebra'],
    'Physics': ['mechanics', 'optics', 'electricity', 'nuclear', 'heat'],
    'Chemistry': ['atoms', 'reactions', 'organic', 'periodic table', 'bonding'],
    'Biology': ['cells', 'genetics', 'ecology', 'anatomy', 'physiology'],
    'English Language': ['grammar', 'vocabulary', 'composition', 'literature', 'phonetics']
  };

  const currentTopics = topics[subjectName] || ['fundamental', 'advanced', 'practical', 'theory', 'application'];

  for (let i = seedQuestions.length + 1; i <= 50; i++) {
    const topic = currentTopics[i % currentTopics.length];
    result.push({
      id: `${subjectName.toLowerCase().replace(/\s/g, '-')}-${i}`,
      text: `Practice Question #${i} for ${subjectName}: Which of the following best describes the ${topic} aspect within the ${level} curriculum context?`,
      options: [
        `Option A: Core ${topic} analysis`,
        `Option B: Practical ${topic} demonstration`,
        `Option C: Theoretical ${topic} framework`,
        `Option D: Interdisciplinary ${topic} study`
      ],
      correctAnswer: i % 4
    });
  }
  return result;
};

