                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                  </svg>
                </button>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => onNavigate('login')}
                  className="text-sm font-bold text-slate-600 hover:text-slate-900 px-4 py-2"
                >
                  Login
                </button>
                <button 
                  onClick={() => onNavigate('register')}
                  className="px-6 py-2 bg-slate-900 text-white rounded-full text-sm font-bold hover:bg-slate-800 transition-all shadow-md"
                >
                  Register
                </button>
              </div>
            )}
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="text-slate-600 hover:text-slate-900 p-2"
            >
              <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                {isOpen ? (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                ) : (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                )}
              </svg>
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Nav */}
      {isOpen && (
        <div className="md:hidden glass-effect border-b">
          <div className="px-2 pt-2 pb-3 space-y-1">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  onNavigate(item.id);
                  setIsOpen(false);
                }}
                className={`block w-full text-left px-3 py-2 rounded-md text-base font-medium ${
                  activePage === item.id ? 'text-amber-600 bg-amber-50' : 'text-slate-600 hover:bg-slate-50'
                }`}
              >
                {item.label}
              </button>
            ))}
            {user ? (
              <button
                onClick={() => {
                  onLogout();
                  setIsOpen(false);
                }}
                className="block w-full text-left px-3 py-2 text-red-600 font-bold"
              >
                Logout
              </button>
            ) : (
              <div className="pt-2 pb-1 border-t border-slate-100">
                <button
                  onClick={() => {
                    onNavigate('login');
                    setIsOpen(false);
                  }}
                  className="block w-full text-left px-3 py-2 text-slate-900 font-bold"
                >
                  Login
                </button>
                <button
                  onClick={() => {
                    onNavigate('register');
                    setIsOpen(false);
                  }}
                  className="block w-full text-left px-3 py-2 text-amber-600 font-bold"
                >
                  Register
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import HomeSlider from './components/HomeSlider';
import CBTEngine from './components/CBTEngine';
import AIAssistant from './components/AIAssistant';
import VirtualClassroom from './components/VirtualClassroom';
import VirtualMeetingRoom from './components/VirtualMeetingRoom';
import ResultsPage from './components/ResultsPage';
import ResultSlip from './components/ResultSlip';
import LoginPage from './components/LoginPage';
import AdminDashboard from './components/AdminDashboard';
import Footer from './components/Footer';
import { SUBJECTS, INITIAL_SCHOOL_CONFIG, TESTIMONIALS } from './constants';
import { Subject, SchoolLevel, User, UserRole, SchoolConfig, Meeting, ExamResult } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('home');
  const [user, setUser] = useState<User | null>(null);
  const [subjects, setSubjects] = useState<Subject[]>(SUBJECTS);
  const [config, setConfig] = useState<SchoolConfig>(INITIAL_SCHOOL_CONFIG);
  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
  const [filterLevel, setFilterLevel] = useState<SchoolLevel | 'all'>('all');
  const [activeMeeting, setActiveMeeting] = useState<Meeting | null>(null);
  const [results, setResults] = useState<ExamResult[]>([]);
  const [viewingResult, setViewingResult] = useState<ExamResult | null>(null);

  const handleStartExam = (subject: Subject) => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    setSelectedSubject(subject);
    setCurrentPage('exam');
  };

  const handleJoinMeeting = (meeting: Meeting) => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    setActiveMeeting(meeting);
    setCurrentPage('classroom');
  };

  const handleSaveResult = (newResult: ExamResult) => {
    setResults(prev => [newResult, ...prev]);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
    setActiveMeeting(null);
    setViewingResult(null);
  };

  const filteredSubjects = filterLevel === 'all' 
    ? subjects 
    : subjects.filter(s => s.level === filterLevel);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Navbar 
        activePage={currentPage} 
        onNavigate={(p) => {
          setCurrentPage(p);
          setSelectedSubject(null);
          setActiveMeeting(null);
          setViewingResult(null);
        }} 
        user={user}
        onLogout={handleLogout}
      />

      <main className="flex-grow">
        {currentPage === 'home' && (
          <>
            <Hero 
              title={config.heroTitle} 
              subtitle={config.heroSubtitle} 
              onStart={() => setCurrentPage('cbt')} 
            />

            <HomeSlider />

            {/* Curriculum Section */}
            <section className="py-20 bg-white border-y">
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
                <h2 className="text-3xl font-bold text-slate-900 mb-4">Global Curriculum Standards</h2>
                <p className="text-slate-600 max-w-2xl mx-auto mb-12">We provide a world-class educational foundation through integrated international standards.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="p-10 rounded-3xl bg-blue-50 border border-blue-100 text-left hover:shadow-lg transition-all">
                    <div className="text-4xl mb-4">🇬🇧</div>
                    <h3 className="text-2xl font-bold text-blue-900 mb-4">British Curriculum</h3>
                    <p className="text-blue-800/70">Our British curriculum (Cambridge) emphasizes structured learning, critical thinking, and prepares students for IGCSE and A-Levels with a focus on depth and knowledge mastery.</p>
                  </div>
                  <div className="p-10 rounded-3xl bg-amber-50 border border-amber-100 text-left hover:shadow-lg transition-all">
                    <div className="text-4xl mb-4">🇺🇸</div>
                    <h3 className="text-2xl font-bold text-amber-900 mb-4">American Curriculum</h3>
                    <p className="text-amber-800/70">The American curriculum promotes holistic development, creativity, and a broad range of subjects, focusing on continuous assessment and preparation for SATs and AP courses.</p>
                  </div>
                </div>
              </div>
            </section>

            <section className="py-20 bg-slate-50">
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="text-center mb-16">
                  <h2 className="text-3xl font-bold text-slate-900 mb-4">Our Learning Levels</h2>
                  <p className="text-slate-600 max-w-2xl mx-auto">From early years to university preparation, we guide every step.</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                  {[
                    { title: SchoolLevel.NURSERY, desc: 'Play-based discovery and foundations.', color: 'bg-pink-100 text-pink-700' },
                    { title: SchoolLevel.GRADE, desc: 'Building core subject confidence.', color: 'bg-blue-100 text-blue-700' },
                    { title: SchoolLevel.JUNIOR_SECONDARY, desc: 'Developing critical academic skills.', color: 'bg-purple-100 text-purple-700' },
                    { title: SchoolLevel.SENIOR_SECONDARY, desc: 'Preparation for global higher education.', color: 'bg-green-100 text-green-700' }
                  ].map((lvl, idx) => (
                    <div key={idx} className="p-8 rounded-3xl border border-slate-100 hover:shadow-xl transition-all hover:-translate-y-1 bg-white">
                      <div className={`w-12 h-12 rounded-full flex items-center justify-center mb-6 font-bold ${lvl.color}`}>
                        {idx + 1}
                      </div>
                      <h3 className="text-xl font-bold text-slate-900 mb-4">{lvl.title}</h3>
                      <p className="text-slate-600 text-sm mb-6">{lvl.desc}</p>
                      <button 
                        onClick={() => {
                          setFilterLevel(lvl.title as SchoolLevel);
                          setCurrentPage('cbt');
                        }}
                        className="text-amber-600 font-semibold text-sm flex items-center group"
                      >
                        Portal 
                        <svg className="w-4 h-4 ml-2 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                        </svg>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            </section>

            {/* Testimonials Section */}
            <section className="py-20 bg-white">
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="text-center mb-16">
                  <h2 className="text-3xl font-bold text-slate-900 mb-4">What Our Community Says</h2>
                  <p className="text-slate-600">Hear from parents and students who experience Christaville excellence.</p>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                  {TESTIMONIALS.map((t) => (
                    <div key={t.id} className="p-6 rounded-3xl border border-slate-100 bg-slate-50 flex flex-col h-full">
                      <div className="flex items-center mb-4">
                        <img src={t.avatar} alt={t.name} className="w-12 h-12 rounded-full mr-3 border-2 border-amber-500" />
                        <div>
                          <h4 className="font-bold text-slate-900 leading-tight">{t.name}</h4>
                          <span className="text-xs text-amber-600 font-medium">{t.role}</span>
                        </div>
                      </div>
                      <p className="text-slate-600 text-sm italic flex-grow">"{t.text}"</p>
                      <div className="mt-4 flex text-amber-400">
                        {"★★★★★".split("").map((s, i) => <span key={i}>{s}</span>)}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </section>
          </>
        )}

        {(currentPage === 'login' || currentPage === 'register') && !user && (
          <LoginPage 
            initialMode={currentPage === 'register' ? 'register' : 'login'}
            onLogin={(u) => {
              setUser(u);
              setCurrentPage(u.role === UserRole.ADMIN ? 'admin' : 'home');
            }} 
          />
        )}

        {currentPage === 'admin' && user?.role === UserRole.ADMIN && (
          <div className="pt-24 pb-20 px-4">
            <AdminDashboard 
              subjects={subjects} 
              setSubjects={setSubjects} 
              config={config} 
              setConfig={setConfig} 
              results={results}
            />
          </div>
        )}

        {currentPage === 'virtual' && (
          <div className="pt-24 pb-20">
            <VirtualClassroom user={user} onJoinMeeting={handleJoinMeeting} />
          </div>
        )}

        {currentPage === 'results' && user && (
          <ResultsPage 
            user={user} 
            results={results} 
            onViewResult={(res) => setViewingResult(res)} 
          />
        )}

        {viewingResult && (
          <ResultSlip 
            result={viewingResult} 
            config={config} 
            onClose={() => setViewingResult(null)} 
          />
        )}

        {currentPage === 'classroom' && activeMeeting && user && (
          <VirtualMeetingRoom 
            user={user} 
            meeting={activeMeeting} 
            onExit={() => {
              setCurrentPage('virtual');
              setActiveMeeting(null);
            }} 
          />
        )}

        {currentPage === 'cbt' && (
          <div className="pt-24 pb-20 px-4 max-w-7xl mx-auto">
            <div className="mb-12 text-center">
              <h2 className="text-4xl font-bold text-slate-900 mb-4">Captivating CBT Portal</h2>
              <p className="text-slate-600 mb-8">Test your skills across all educational levels. Choose your stage below.</p>

              <div className="flex flex-wrap justify-center gap-2">
                {['all', ...Object.values(SchoolLevel)].map((lvl) => (
                  <button
                    key={lvl}
                    onClick={() => setFilterLevel(lvl as any)}
                    className={`px-6 py-2 rounded-full text-sm font-medium transition-all ${
                      filterLevel === lvl 
                        ? 'bg-slate-900 text-white shadow-md' 
                        : 'bg-white border text-slate-600 hover:bg-slate-50 shadow-sm'
                    }`}
                  >
                    {lvl}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredSubjects.map((sub) => (
                <div key={sub.id} className="glass-effect p-6 rounded-2xl border shadow-sm hover:shadow-lg transition-all flex flex-col group">
                  <div className="text-4xl mb-4 group-hover:scale-110 transition-transform">{sub.icon}</div>
                  <h3 className="text-lg font-bold text-slate-900 mb-1">{sub.name}</h3>
                  <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded mb-4 inline-block w-fit ${
                    sub.level === SchoolLevel.NURSERY ? 'bg-pink-100 text-pink-700' :
                    sub.level === SchoolLevel.GRADE ? 'bg-blue-100 text-blue-700' :
                    sub.level === SchoolLevel.JUNIOR_SECONDARY ? 'bg-purple-100 text-purple-700' :
                    'bg-green-100 text-green-700'
                  }`}>
                    {sub.level}
                  </span>
                  <p className="text-slate-500 text-xs mb-6 mt-auto">{sub.questions.length} Practice Questions</p>
                  <button
                    onClick={() => handleStartExam(sub)}
                    className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-amber-600 transition-colors shadow-lg text-sm"
                  >
                    Start Assessment
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {currentPage === 'exam' && selectedSubject && user && (
          <div className="pt-24 pb-20 px-4">
            <CBTEngine 
              subject={selectedSubject} 
              user={user}
              onExit={() => {
                setCurrentPage('cbt');
                setSelectedSubject(null);
              }} 
              onSaveResult={handleSaveResult}
            />
          </div>
        )}

        {currentPage === 'tutor' && (
          <div className="pt-24 pb-20 px-4">
            <div className="text-center mb-12">
              <h2 className="text-4xl font-bold text-slate-900 mb-4">Personalized AI Tutoring</h2>
              <p className="text-slate-600">Global curricula expert available 24/7 to help you excel.</p>
            </div>
            <AIAssistant />
          </div>
        )}

        {currentPage === 'about' && (
          <div className="pt-32 pb-20 px-4 max-w-4xl mx-auto text-center">
            <h2 className="text-4xl font-bold text-slate-900 mb-8">About {config.schoolName}</h2>
            <div className="glass-effect p-10 rounded-3xl text-left space-y-6 shadow-2xl">
              <p className="text-lg text-slate-600 leading-relaxed">
                {config.aboutText}
              </p>
              <img src="https://images.unsplash.com/photo-1509062522246-3755977927d7?auto=format&fit=crop&q=80&w=1200" alt="School" className="rounded-2xl w-full h-80 object-cover shadow-lg" />
              <div className="grid grid-cols-2 gap-4">
                 <div className="p-4 bg-slate-50 rounded-2xl border">
                    <h4 className="font-bold text-slate-900">British Pathway</h4>
                    <p className="text-sm text-slate-500">Cambridge Primary and Secondary curricula.</p>
                 </div>
                 <div className="p-4 bg-slate-50 rounded-2xl border">
                    <h4 className="font-bold text-slate-900">American Pathway</h4>
                    <p className="text-sm text-slate-500">Common Core standards and SAT preparation.</p>
                 </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Subject, SchoolConfig, ExamResult } from '../types';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  config: SchoolConfig;
  setConfig: React.Dispatch<React.SetStateAction<SchoolConfig>>;
  results: ExamResult[];
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ subjects, setSubjects, config, setConfig, results }) => {
  const [activeTab, setActiveTab] = useState<'content' | 'cbt' | 'results'>('content');

  const handleConfigChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setConfig(prev => ({ ...prev, [name]: value }));
  };

  const handleDeleteSubject = (id: string) => {
    if (window.confirm('Are you sure you want to delete this subject?')) {
      setSubjects(subjects.filter(s => s.id !== id));
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-4 print:hidden">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Admin Control Center</h2>
          <p className="text-slate-600">Managing Christaville School Digital Hub</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl w-full md:w-auto overflow-x-auto">
          <button 
            onClick={() => setActiveTab('content')}
            className={`whitespace-nowrap px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'content' ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Site Content
          </button>
          <button 
            onClick={() => setActiveTab('cbt')}
            className={`whitespace-nowrap px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'cbt' ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
          >
            CBT Portal
          </button>
          <button 
            onClick={() => setActiveTab('results')}
            className={`whitespace-nowrap px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'results' ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Exam Results
          </button>
        </div>
      </div>

      {activeTab === 'content' && (
        <div className="space-y-6 animate-in fade-in duration-500">
          <div className="glass-effect p-8 rounded-3xl border shadow-sm">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <span className="p-2 bg-blue-50 text-blue-600 rounded-lg">🏠</span>
              Hero Section Settings
            </h3>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Main Hero Title</label>
