                  type="text" 
                  name="heroTitle"
                  value={config.heroTitle}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Hero Subtitle</label>
                <textarea 
                  name="heroSubtitle"
                  rows={3}
                  value={config.heroSubtitle}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>
          </div>

          <div className="glass-effect p-8 rounded-3xl border shadow-sm">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <span className="p-2 bg-amber-50 text-amber-600 rounded-lg">📖</span>
              About Us Section
            </h3>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Description Text</label>
              <textarea 
                name="aboutText"
                rows={5}
                value={config.aboutText}
                onChange={handleConfigChange}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none"
              />
            </div>
          </div>
        </div>
      )}

      {activeTab === 'cbt' && (
        <div className="space-y-4 animate-in fade-in duration-500">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-xl font-bold text-slate-900">Current Subjects</h3>
            <button className="px-4 py-2 bg-green-600 text-white rounded-lg text-sm font-bold hover:bg-green-700 transition-all">
              + New Subject
            </button>
          </div>
          <div className="grid grid-cols-1 gap-4">
            {subjects.map((sub) => (
              <div key={sub.id} className="glass-effect p-6 rounded-2xl border flex flex-col md:flex-row justify-between items-center gap-4 hover:border-slate-300 transition-colors">
                <div className="flex items-center gap-4">
                  <span className="text-4xl w-12 h-12 flex items-center justify-center bg-slate-50 rounded-xl">{sub.icon}</span>
                  <div>
                    <h4 className="font-bold text-lg text-slate-900">{sub.name}</h4>
                    <p className="text-sm text-slate-500">{sub.level} • {sub.questions.length} Questions</p>
