                      <th className="px-6 py-4">Class</th>
                      <th className="px-6 py-4">Subject</th>
                      <th className="px-6 py-4">Score</th>
                      <th className="px-6 py-4">Grade</th>
                      <th className="px-6 py-4">Date</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y text-sm">
                    {results.length === 0 ? (
                      <tr>
                        <td colSpan={6} className="px-6 py-10 text-center text-slate-400 font-medium">No official results have been recorded yet.</td>
                      </tr>
                    ) : (
                      results.map(res => (
                        <tr key={res.id} className="hover:bg-slate-50 transition-colors">
                          <td className="px-6 py-4 font-bold text-slate-900">{res.studentName}</td>
                          <td className="px-6 py-4 text-slate-500">{res.studentClass}</td>
                          <td className="px-6 py-4 text-slate-500 font-medium">{res.subjectName}</td>
                          <td className="px-6 py-4 font-black">{res.percentage}%</td>
                          <td className="px-6 py-4">
                            <span className={`px-2 py-1 rounded text-xs font-bold ${res.grade === 'A' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-700'}`}>
                              {res.grade}
                            </span>
                          </td>
                          <td className="px-6 py-4 text-slate-400 text-xs">{res.date}</td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

