                                 title="Delete Result"
                               >
                                 <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                               </button>
                             </div>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
             </div>
          </div>
        </div>
      )}

      {/* Edit Result Modal */}
      {editingResult && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Edit Student Result</h3>
                <p className="text-xs text-slate-500 uppercase font-bold tracking-widest mt-1">{editingResult.studentName}</p>
              </div>
              <button onClick={() => setEditingResult(null)} className="text-slate-400 hover:text-slate-600 transition-colors p-2">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <form onSubmit={handleUpdateResult} className="space-y-6">
              <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                 <p className="text-xs font-bold text-slate-400 uppercase mb-2">Subject Details</p>
                 <p className="text-sm font-bold text-slate-700">{editingResult.subjectName} ({editingResult.subjectLevel})</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Achieved Score</label>
                  <input 
                    type="number"
                    required
                    min="0"
                    max={editingResult.totalQuestions}
                    value={editingResult.score}
                    onChange={(e) => setEditingResult({...editingResult, score: parseInt(e.target.value) || 0})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none font-bold text-lg"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Total Possible</label>
                  <input 
                    type="number"
                    disabled
                    value={editingResult.totalQuestions}
                    className="w-full px-4 py-3 rounded-xl border border-slate-100 bg-slate-50 text-slate-400 outline-none font-bold text-lg cursor-not-allowed"
                  />
                </div>
              </div>

              <div className="flex items-center gap-4 p-4 bg-amber-50 rounded-2xl border border-amber-100">
                 <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center font-black text-amber-600 shadow-sm border border-amber-200">
                   {getGrade(Math.round((editingResult.score / editingResult.totalQuestions) * 100))}
                 </div>
                 <div>
                    <p className="text-[10px] font-bold text-amber-600 uppercase">Live Grade Calculation</p>
                    <p className="text-sm font-bold text-amber-900">{Math.round((editingResult.score / editingResult.totalQuestions) * 100)}% Proficiency</p>
                 </div>
              </div>

              <div className="flex gap-3">
                <button 
                  type="button" 
                  onClick={() => setEditingResult(null)}
                  className="flex-1 py-3 border border-slate-200 rounded-xl font-bold text-slate-600 hover:bg-slate-50 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-amber-600 shadow-lg transition-all"
                >
                  Update Result
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

