  STUDENT = 'Student',
  PARENT = 'Parent',
  TEACHER = 'Teacher',
  ADMIN = 'Admin'
}

export enum AttendanceStatus {
  PRESENT = 'Present',
  ABSENT = 'Absent',
  LATE = 'Late'
}

export interface User {
