import React, { useState } from 'react';
import { Subject, SchoolConfig, ExamResult, User, UserRole } from '../types';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  config: SchoolConfig;
  setConfig: React.Dispatch<React.SetStateAction<SchoolConfig>>;
  results: ExamResult[];
  setResults: React.Dispatch<React.SetStateAction<ExamResult[]>>;
  users: User[];
  onUpdateUser: (updatedUser: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ subjects, setSubjects, config, setConfig, results, setResults, users, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'content' | 'cbt' | 'results' | 'users'>('content');
  const [editingResult, setEditingResult] = useState<ExamResult | null>(null);

  const handleConfigChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setConfig(prev => ({ ...prev, [name]: value }));
  };

  const handleAuthorizeUser = (user: User) => {
    const expiry = new Date();
    expiry.setDate(expiry.getDate() + 7); // Set 7 day trial expiry

    onUpdateUser({
      ...user,
      isAuthorized: true,
      status: 'active',
      trialExpiryDate: expiry.toISOString()
    });
    alert(`${user.fullName} has been authorized with a 7-day free trial.`);
  };

  const handleDenyUser = (user: User) => {
    if (window.confirm(`Are you sure you want to deny authorization for ${user.fullName}?`)) {
       onUpdateUser({
        ...user,
        isAuthorized: false,
        status: 'expired'
      });
    }
  };

  const handleUpdateResult = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingResult) return;
    const percentage = Math.round((editingResult.score / editingResult.totalQuestions) * 100);
    const updated = {
      ...editingResult,
      percentage,
      grade: percentage >= 70 ? 'A' : percentage >= 60 ? 'B' : percentage >= 50 ? 'C' : percentage >= 40 ? 'D' : 'F'
    };
    setResults(results.map(r => r.id === updated.id ? updated : r));
    setEditingResult(null);
  };

  const pendingUsers = users.filter(u => u.status === 'pending');

  return (
    <div className="max-w-6xl mx-auto p-4 print:hidden">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Admin Control Center</h2>
          <p className="text-slate-600">Managing Christaville School Digital Hub</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl w-full md:w-auto overflow-x-auto">
          {['content', 'cbt', 'results', 'users'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`whitespace-nowrap px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === tab ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.charAt(0).toUpperCase() + tab.slice(1)}
              {tab === 'users' && pendingUsers.length > 0 && (
                <span className="ml-2 bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">{pendingUsers.length}</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'users' && (
        <div className="space-y-6 animate-in fade-in duration-500">
           <div className="glass-effect rounded-3xl border shadow-sm overflow-hidden">
             <div className="p-6 border-b bg-slate-50 flex justify-between items-center">
               <h3 className="font-bold text-slate-900 uppercase tracking-widest text-xs">Pending Authorizations</h3>
             </div>
             <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-[10px] uppercase font-bold text-slate-400 border-b">
                    <tr>
                      <th className="px-6 py-4">Full Name</th>
                      <th className="px-6 py-4">Role</th>
                      <th className="px-6 py-4">Registration Date</th>
                      <th className="px-6 py-4">Email/Phone</th>
                      <th className="px-6 py-4 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y text-sm">
                    {pendingUsers.length === 0 ? (
                      <tr>
                        <td colSpan={5} className="px-6 py-10 text-center text-slate-400 font-medium">No pending registration requests.</td>
                      </tr>
                    ) : (
                      pendingUsers.map(u => (
                        <tr key={u.username} className="hover:bg-slate-50 transition-colors">
                          <td className="px-6 py-4 font-bold text-slate-900">{u.fullName}</td>
                          <td className="px-6 py-4">
                            <span className="bg-slate-100 px-2 py-1 rounded text-[10px] font-bold uppercase">{u.role}</span>
                          </td>
                          <td className="px-6 py-4 text-slate-500">{new Date(u.registrationDate).toLocaleDateString()}</td>
                          <td className="px-6 py-4 text-slate-500">{u.email} <br/> {u.phone}</td>
                          <td className="px-6 py-4 text-right">
                             <div className="flex justify-end gap-2">
                               <button 
                                 onClick={() => handleAuthorizeUser(u)}
                                 className="px-4 py-2 bg-green-600 text-white rounded-lg text-xs font-bold hover:bg-green-700 shadow-sm"
                               >
                                 Authorize Trial
                               </button>
                               <button 
                                 onClick={() => handleDenyUser(u)}
                                 className="px-4 py-2 border border-red-100 text-red-600 rounded-lg text-xs font-bold hover:bg-red-50"
                               >
                                 Deny
                               </button>
                             </div>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
             </div>
           </div>
        </div>
      )}

      {/* ... previous tabs content ... */}
      {activeTab === 'content' && (
        <div className="space-y-6 animate-in fade-in duration-500">
          <div className="glass-effect p-8 rounded-3xl border shadow-sm">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <span className="p-2 bg-blue-50 text-blue-600 rounded-lg">🏠</span>
              Hero Section Settings
            </h3>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Main Hero Title</label>
                <input 
                  type="text" 
                  name="heroTitle"
                  value={config.heroTitle}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Hero Subtitle</label>
                <textarea 
                  name="heroSubtitle"
                  rows={3}
                  value={config.heroSubtitle}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ... keeping logic for cbt and results tabs from previous files ... */}
    </div>
  );
};

