import React, { useState } from 'react';
import { Subject, SchoolConfig, ExamResult, User, UserRole, SchoolLevel } from '../types';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  config: SchoolConfig;
  setConfig: React.Dispatch<React.SetStateAction<SchoolConfig>>;
  results: ExamResult[];
  setResults: React.Dispatch<React.SetStateAction<ExamResult[]>>;
  users: User[];
  onUpdateUser: (updatedUser: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  subjects, 
  setSubjects, 
  config, 
  setConfig, 
  results, 
  setResults, 
  users, 
  onUpdateUser 
}) => {
  const [activeTab, setActiveTab] = useState<'content' | 'cbt' | 'results' | 'users'>('content');
  const [editingResult, setEditingResult] = useState<ExamResult | null>(null);
  const [editingSubject, setEditingSubject] = useState<Subject | null>(null);

  const handleConfigChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setConfig(prev => ({ ...prev, [name]: value }));
  };

  const handleAuthorizeUser = (user: User) => {
    const expiry = new Date();
    expiry.setDate(expiry.getDate() + 7); // Set 7 day trial expiry

    onUpdateUser({
      ...user,
      isAuthorized: true,
      status: 'active',
      trialExpiryDate: expiry.toISOString()
    });
    alert(`${user.fullName} has been authorized with a 7-day free trial.`);
  };

  const handleDenyUser = (user: User) => {
    if (window.confirm(`Are you sure you want to deny authorization for ${user.fullName}?`)) {
       onUpdateUser({
        ...user,
        isAuthorized: false,
        status: 'expired'
      });
    }
  };

  const getGrade = (percentage: number) => {
    if (percentage >= 70) return 'A';
    if (percentage >= 60) return 'B';
    if (percentage >= 50) return 'C';
    if (percentage >= 40) return 'D';
    return 'F';
  };

  // Subject Update Logic
  const handleUpdateSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingSubject) return;
    setSubjects(subjects.map(s => s.id === editingSubject.id ? editingSubject : s));
    setEditingSubject(null);
  };

  // Result Update Logic
  const handleUpdateResult = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingResult) return;
    const percentage = Math.round((editingResult.score / editingResult.totalQuestions) * 100);
    const updated = {
      ...editingResult,
      percentage,
      grade: getGrade(percentage)
    };
    setResults(results.map(r => r.id === updated.id ? updated : r));
    setEditingResult(null);
  };

  const handleDeleteSubject = (id: string) => {
    if (window.confirm('Are you sure you want to delete this subject? All associated questions will be lost.')) {
      setSubjects(subjects.filter(s => s.id !== id));
    }
  };

  const handleDeleteResult = (id: string) => {
    if (window.confirm('Delete this official student result? This action cannot be undone.')) {
      setResults(results.filter(r => r.id !== id));
    }
  };

  const generateNewPin = () => {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let pin = 'CV-';
    for (let i = 0; i < 4; i++) {
      pin += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    if (editingResult) {
      setEditingResult({...editingResult, pin});
    }
  };

  const pendingUsers = users.filter(u => u.status === 'pending');

  return (
    <div className="max-w-6xl mx-auto p-4 print:hidden">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Admin Control Center</h2>
          <p className="text-slate-600 font-medium">Logged in as: <span className="text-amber-600 font-bold">sabatex1979</span></p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl w-full md:w-auto overflow-x-auto shadow-inner">
          {['content', 'cbt', 'results', 'users'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`whitespace-nowrap px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === tab ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.charAt(0).toUpperCase() + tab.slice(1)}
              {tab === 'users' && pendingUsers.length > 0 && (
                <span className="ml-2 bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">{pendingUsers.length}</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'content' && (
        <div className="space-y-6 animate-in fade-in duration-500">
          <div className="glass-effect p-8 rounded-[2rem] border shadow-sm border-white">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <span className="p-2 bg-blue-50 text-blue-600 rounded-lg">🏠</span>
              Hero Section Settings
            </h3>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2">School Name</label>
                <input 
                  type="text" 
                  name="schoolName"
                  value={config.schoolName}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold"
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2">Main Hero Title</label>
                <input 
                  type="text" 
                  name="heroTitle"
                  value={config.heroTitle}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2">Hero Subtitle</label>
                <textarea 
                  name="heroSubtitle"
                  rows={3}
                  value={config.heroSubtitle}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>
          </div>

          <div className="glass-effect p-8 rounded-[2rem] border shadow-sm border-white">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <span className="p-2 bg-amber-50 text-amber-600 rounded-lg">📖</span>
