            <form onSubmit={handleUpdateSubject} className="space-y-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Subject Name</label>
                <input 
                  type="text"
                  required
                  value={editingSubject.name}
                  onChange={(e) => setEditingSubject({...editingSubject, name: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none font-bold"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Visual Icon (Emoji)</label>
                <input 
                  type="text"
                  required
                  value={editingSubject.icon}
                  onChange={(e) => setEditingSubject({...editingSubject, icon: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none text-2xl"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Academic Level</label>
                <select 
                  value={editingSubject.level}
                  onChange={(e) => setEditingSubject({...editingSubject, level: e.target.value as SchoolLevel})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none font-bold bg-white"
                >
                  {Object.values(SchoolLevel).map(lvl => <option key={lvl} value={lvl}>{lvl}</option>)}
                </select>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setEditingSubject(null)} className="flex-1 py-3 border border-slate-200 rounded-xl font-bold text-slate-500 hover:bg-slate-50">Cancel</button>
                <button type="submit" className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-amber-600 shadow-xl">Apply Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Edit Result Modal */}
      {editingResult && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md p-8 rounded-[2.5rem] shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-2xl font-bold text-slate-900 mb-6">Edit Terminal Result</h3>
            <form onSubmit={handleUpdateResult} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Achieved Score</label>
                  <input 
                    type="number"
                    required
                    min="0"
                    max={editingResult.totalQuestions}
                    value={editingResult.score}
                    onChange={(e) => setEditingResult({...editingResult, score: parseInt(e.target.value) || 0})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none font-bold text-lg"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Access PIN</label>
                  <div className="flex gap-2">
                    <input 
                      type="text"
                      required
                      value={editingResult.pin}
                      onChange={(e) => setEditingResult({...editingResult, pin: e.target.value.toUpperCase()})}
                      className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none font-mono font-bold uppercase text-xs"
                    />
                    <button type="button" onClick={generateNewPin} className="p-3 bg-slate-100 rounded-xl text-slate-500 hover:bg-slate-200"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
                  </div>
                </div>
              </div>

              <div className="p-4 bg-amber-50 rounded-2xl border border-amber-100 flex items-center justify-between">
                 <div>
                    <p className="text-[10px] font-black text-amber-600 uppercase">Live Grade Status</p>
                    <p className="text-sm font-bold text-amber-900">{Math.round((editingResult.score / editingResult.totalQuestions) * 100)}% Proficiency</p>
                 </div>
                 <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center font-black text-amber-600 border border-amber-200 shadow-sm text-xl">
                   {getGrade(Math.round((editingResult.score / editingResult.totalQuestions) * 100))}
                 </div>
              </div>

              <div className="flex gap-3">
                <button type="button" onClick={() => setEditingResult(null)} className="flex-1 py-3 border border-slate-200 rounded-xl font-bold text-slate-500 hover:bg-slate-50">Discard</button>
                <button type="submit" className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-amber-600 shadow-xl">Update Record</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

