                        <svg className="w-4 h-4 ml-2 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                        </svg>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            </section>
          </>
        )}

        {(currentPage === 'login' || currentPage === 'register') && !user && (
          <LoginPage 
            initialMode={currentPage === 'register' ? 'register' : 'login'}
            onLogin={(u) => {
              setUser(u);
              setCurrentPage('home');
            }} 
          />
        )}

        {currentPage === 'admin' && user?.role === UserRole.ADMIN && (
          <div className="pt-24 pb-20 px-4">
            <AdminDashboard 
              subjects={subjects} 
              setSubjects={setSubjects} 
              config={config} 
              setConfig={setConfig} 
              results={results}
              setResults={setResults}
              users={allUsers}
              onUpdateUser={handleUpdateUser}
            />
          </div>
        )}

        {currentPage === 'virtual' && user?.isAuthorized && (
          <div className="pt-24 pb-20">
            <VirtualClassroom user={user} onJoinMeeting={handleJoinMeeting} />
          </div>
        )}

        {currentPage === 'results' && user?.isAuthorized && (
          <ResultsPage 
            user={user} 
            results={results} 
            onViewResult={(res) => setViewingResult(res)} 
          />
        )}

        {currentPage === 'attendance' && user?.isAuthorized && (
          <AttendancePage 
            user={user} 
            records={attendance} 
            onMarkAttendance={handleMarkAttendance} 
          />
        )}

        {currentPage === 'cbt' && user?.isAuthorized && (
          <div className="pt-24 pb-20 px-4 max-w-7xl mx-auto">
             <div className="mb-12 text-center">
              <h2 className="text-4xl font-bold text-slate-900 mb-4">Captivating CBT Portal</h2>
              <p className="text-slate-600 mb-8">Test your skills across all educational levels. Choose your stage below.</p>

              <div className="flex flex-wrap justify-center gap-2">
                {['all', ...Object.values(SchoolLevel)].map((lvl) => (
                  <button
                    key={lvl}
                    onClick={() => setFilterLevel(lvl as any)}
                    className={`px-6 py-2 rounded-full text-sm font-medium transition-all ${
                      filterLevel === lvl 
                        ? 'bg-slate-900 text-white shadow-md' 
                        : 'bg-white border text-slate-600 hover:bg-slate-50 shadow-sm'
                    }`}
                  >
                    {lvl}
                  </button>
                ))}
              </div>
            </div>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredSubjects.map((sub) => (
                <div key={sub.id} className="glass-effect p-6 rounded-2xl border shadow-sm hover:shadow-lg transition-all flex flex-col group">
                  <div className="text-4xl mb-4 group-hover:scale-110 transition-transform">{sub.icon}</div>
                  <h3 className="text-lg font-bold text-slate-900 mb-1">{sub.name}</h3>
                  <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded mb-4 inline-block w-fit ${
                    sub.level === SchoolLevel.NURSERY ? 'bg-pink-100 text-pink-700' :
                    sub.level === SchoolLevel.GRADE ? 'bg-blue-100 text-blue-700' :
                    sub.level === SchoolLevel.JUNIOR_SECONDARY ? 'bg-purple-100 text-purple-700' :
                    'bg-green-100 text-green-700'
                  }`}>
                    {sub.level}
                  </span>
                  <p className="text-slate-500 text-xs mb-6 mt-auto">{sub.questions.length} Practice Questions</p>
                  <button
                    onClick={() => handleStartExam(sub)}
                    className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-amber-600 transition-colors shadow-lg text-sm"
                  >
                    Start Assessment
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {currentPage === 'exam' && selectedSubject && user?.isAuthorized && (
          <div className="pt-24 pb-20 px-4">
            <CBTEngine 
              subject={selectedSubject} 
              user={user}
              onExit={() => {
                setCurrentPage('cbt');
                setSelectedSubject(null);
              }} 
              onSaveResult={handleSaveResult}
            />
          </div>
        )}

        {currentPage === 'tutor' && user?.isAuthorized && (
          <div className="pt-24 pb-20 px-4">
            <div className="text-center mb-12">
              <h2 className="text-4xl font-bold text-slate-900 mb-4">Personalized AI Tutoring</h2>
              <p className="text-slate-600">Global curricula expert available 24/7 to help you excel.</p>
            </div>
            <AIAssistant />
          </div>
        )}

        {currentPage === 'about' && (
           <div className="pt-32 pb-20 px-4 max-w-4xl mx-auto text-center">
            <h2 className="text-4xl font-bold text-slate-900 mb-8">About {config.schoolName}</h2>
            <div className="glass-effect p-10 rounded-3xl text-left space-y-6 shadow-2xl">
              <p className="text-lg text-slate-600 leading-relaxed">
                {config.aboutText}
              </p>
              <img src="https://images.unsplash.com/photo-1509062522246-3755977927d7?auto=format&fit=crop&q=80&w=1200" alt="School" className="rounded-2xl w-full h-80 object-cover shadow-lg" />
              <div className="grid grid-cols-2 gap-4">
                 <div className="p-4 bg-slate-50 rounded-2xl border">
                    <h4 className="font-bold text-slate-900">British Pathway</h4>
                    <p className="text-sm text-slate-500">Cambridge Primary and Secondary curricula.</p>
                 </div>
                 <div className="p-4 bg-slate-50 rounded-2xl border">
                    <h4 className="font-bold text-slate-900">American Pathway</h4>
                    <p className="text-sm text-slate-500">Common Core standards and SAT preparation.</p>
                 </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Subject, SchoolConfig, ExamResult, User, UserRole, SchoolLevel } from '../types';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  config: SchoolConfig;
  setConfig: React.Dispatch<React.SetStateAction<SchoolConfig>>;
  results: ExamResult[];
  setResults: React.Dispatch<React.SetStateAction<ExamResult[]>>;
  users: User[];
  onUpdateUser: (updatedUser: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  subjects, 
  setSubjects, 
  config, 
  setConfig, 
  results, 
  setResults, 
  users, 
  onUpdateUser 
}) => {
  const [activeTab, setActiveTab] = useState<'content' | 'cbt' | 'results' | 'users'>('users');
  const [editingResult, setEditingResult] = useState<ExamResult | null>(null);
  const [editingSubject, setEditingSubject] = useState<Subject | null>(null);

  const handleConfigChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setConfig(prev => ({ ...prev, [name]: value }));
  };

  const handleAuthorizeUser = (user: User) => {
    onUpdateUser({
      ...user,
      isAuthorized: true
    });
  };

  const handleRevokeUser = (user: User) => {
    if (window.confirm(`Revoke portal access for ${user.fullName}?`)) {
       onUpdateUser({
        ...user,
        isAuthorized: false
      });
    }
  };

  const getGrade = (percentage: number) => {
    if (percentage >= 70) return 'A';
    if (percentage >= 60) return 'B';
    if (percentage >= 50) return 'C';
    if (percentage >= 40) return 'D';
    return 'F';
  };

  const handleUpdateSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingSubject) return;
    setSubjects(subjects.map(s => s.id === editingSubject.id ? editingSubject : s));
    setEditingSubject(null);
  };

  const handleUpdateResult = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingResult) return;
    const percentage = Math.round((editingResult.score / editingResult.totalQuestions) * 100);
    const updated = {
      ...editingResult,
      percentage,
      grade: getGrade(percentage)
    };
    setResults(results.map(r => r.id === updated.id ? updated : r));
    setEditingResult(null);
  };

  const handleDeleteSubject = (id: string) => {
    if (window.confirm('Are you sure you want to delete this subject?')) {
      setSubjects(subjects.filter(s => s.id !== id));
    }
  };

  const handleDeleteResult = (id: string) => {
    if (window.confirm('Delete this official student result?')) {
      setResults(results.filter(r => r.id !== id));
    }
  };

  const generateNewPin = () => {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let pin = 'CV-';
    for (let i = 0; i < 4; i++) {
      pin += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    if (editingResult) {
      setEditingResult({...editingResult, pin});
    }
  };

  const pendingUsers = users.filter(u => !u.isAuthorized && u.role !== UserRole.ADMIN);
  const authorizedUsers = users.filter(u => u.isAuthorized && u.role !== UserRole.ADMIN);

  return (
    <div className="max-w-6xl mx-auto p-4 print:hidden">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Christaville Admin Dashboard</h2>
          <p className="text-slate-600 font-medium">Verified Admin: <span className="text-amber-600 font-bold">sabatex1979</span></p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl w-full md:w-auto overflow-x-auto shadow-inner">
          {['users', 'results', 'cbt', 'content'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`whitespace-nowrap px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === tab ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab === 'users' ? 'User Verification' : tab === 'cbt' ? 'CBT Manager' : tab.charAt(0).toUpperCase() + tab.slice(1)}
              {tab === 'users' && pendingUsers.length > 0 && (
                <span className="ml-2 bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full animate-pulse">{pendingUsers.length}</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'users' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          {/* Pending Verification */}
          <section className="glass-effect rounded-[2rem] border-2 border-amber-100 shadow-xl overflow-hidden bg-amber-50/20">
             <div className="p-6 border-b border-amber-100 flex justify-between items-center bg-amber-50/50">
               <div className="flex items-center gap-3">
                 <span className="w-8 h-8 rounded-lg bg-amber-100 text-amber-600 flex items-center justify-center font-bold">!</span>
                 <h3 className="font-black text-slate-900 uppercase tracking-widest text-xs">Awaiting Verification</h3>
               </div>
               <span className="text-[10px] font-bold text-amber-700 uppercase">{pendingUsers.length} New Requests</span>
             </div>
             <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50/50 text-[10px] uppercase font-bold text-slate-400 border-b">
                    <tr>
                      <th className="px-6 py-4">Applicant</th>
                      <th className="px-6 py-4">Role</th>
                      <th className="px-6 py-4">Details</th>
                      <th className="px-6 py-4 text-right">Verification Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y text-sm bg-white/40">
                    {pendingUsers.length === 0 ? (
                      <tr>
                        <td colSpan={4} className="px-6 py-12 text-center text-slate-400 font-medium italic">All accounts have been verified. No pending requests.</td>
                      </tr>
                    ) : (
                      pendingUsers.map(u => (
                        <tr key={u.username} className="hover:bg-amber-50/50 transition-colors">
                          <td className="px-6 py-5">
                             <p className="font-bold text-slate-900">{u.fullName}</p>
                             <p className="text-[10px] text-slate-400 font-mono">ID: {u.username}</p>
                          </td>
                          <td className="px-6 py-5">
                            <span className="px-2 py-1 rounded text-[10px] font-bold uppercase tracking-widest bg-amber-100 text-amber-700 border border-amber-200">{u.role}</span>
                          </td>
                          <td className="px-6 py-5">
                            <p className="text-xs text-slate-600">{u.email}</p>
                            <p className="text-[10px] text-slate-400">{u.phone}</p>
                          </td>
                          <td className="px-6 py-5 text-right">
                             <div className="flex justify-end gap-2">
                               <button 
                                 onClick={() => handleAuthorizeUser(u)} 
                                 className="px-6 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-green-600 transition-all shadow-md active:scale-95"
                               >
                                 Verify & Authorize
                               </button>
                               <button 
                                 onClick={() => handleRevokeUser(u)} 
                                 className="px-4 py-2 border border-red-100 text-red-500 rounded-xl text-xs font-bold hover:bg-red-50 transition-all"
                               >
                                 Ignore
                               </button>
                             </div>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
             </div>
          </section>

          {/* Active Members */}
          <section className="glass-effect rounded-[2rem] border border-white shadow-lg overflow-hidden">
             <div className="p-6 border-b bg-slate-50/50">
               <h3 className="font-bold text-slate-900 uppercase tracking-widest text-xs">Verified Portal Members</h3>
             </div>
             <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50/50 text-[10px] uppercase font-bold text-slate-400 border-b">
                    <tr>
                      <th className="px-6 py-4">Member Name</th>
                      <th className="px-6 py-4">Role</th>
                      <th className="px-6 py-4">Auth Status</th>
                      <th className="px-6 py-4 text-right">Manage</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y text-sm">
                    {authorizedUsers.map(u => (
                      <tr key={u.username} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-6 py-4 font-bold text-slate-700">{u.fullName}</td>
                        <td className="px-6 py-4">
                          <span className="px-2 py-1 rounded text-[10px] font-bold bg-slate-100 text-slate-500 uppercase tracking-tighter">{u.role}</span>
                        </td>
                        <td className="px-6 py-4">
                           <span className="flex items-center gap-1.5 text-[10px] font-bold text-green-600 uppercase">
                             <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                             Verified
                           </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                           <button 
                            onClick={() => handleRevokeUser(u)} 
                            className="text-[10px] text-red-400 hover:text-red-600 uppercase font-black tracking-widest transition-colors"
                           >
                             Revoke Access
                           </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </section>
        </div>
      )}

      {/* Keep other tabs as defined in previous versions */}
      {activeTab === 'content' && (
        <div className="space-y-6 animate-in fade-in duration-500">
          <div className="glass-effect p-8 rounded-[2rem] border shadow-sm border-white">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <span className="p-2 bg-blue-50 text-blue-600 rounded-lg">🏠</span>
              Hero Section Settings
            </h3>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2">School Name</label>
                <input 
                  type="text" 
                  name="schoolName"
                  value={config.schoolName}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold"
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2">Main Hero Title</label>
                <input 
                  type="text" 
                  name="heroTitle"
                  value={config.heroTitle}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2">Hero Subtitle</label>
                <textarea 
                  name="heroSubtitle"
                  rows={3}
                  value={config.heroSubtitle}
                  onChange={handleConfigChange}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modals for editing results and subjects go here (as per previous turn) */}
      {editingResult && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md p-8 rounded-[2.5rem] shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-2xl font-bold text-slate-900 mb-6">Edit Terminal Result</h3>
            <form onSubmit={handleUpdateResult} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Score</label>
                  <input 
                    type="number"
                    value={editingResult.score}
                    onChange={(e) => setEditingResult({...editingResult, score: parseInt(e.target.value) || 0})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none font-bold text-lg"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">PIN</label>
                  <div className="flex gap-2">
                    <input 
                      type="text"
                      value={editingResult.pin}
                      onChange={(e) => setEditingResult({...editingResult, pin: e.target.value.toUpperCase()})}
                      className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-amber-500 outline-none font-mono font-bold uppercase text-xs"
                    />
                    <button type="button" onClick={generateNewPin} className="p-3 bg-slate-100 rounded-xl text-slate-500"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
                  </div>
                </div>
              </div>
              <div className="flex gap-3">
                <button type="button" onClick={() => setEditingResult(null)} className="flex-1 py-3 border border-slate-200 rounded-xl font-bold text-slate-500 hover:bg-slate-50">Discard</button>
                <button type="submit" className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-amber-600 shadow-xl">Update</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

