import { Subject, SchoolLevel, User, UserRole, SchoolConfig, Meeting, ExamResult, AttendanceRecord, Testimonial } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('home');
  const [user, setUser] = useState<User | null>(null);
  const [allUsers, setAllUsers] = useState<User[]>([]); 
  const [subjects, setSubjects] = useState<Subject[]>(SUBJECTS);
  const [config, setConfig] = useState<SchoolConfig>(INITIAL_SCHOOL_CONFIG);
  const [slides, setSlides] = useState(INITIAL_SLIDES);
  const [testimonials, setTestimonials] = useState<Testimonial[]>(INITIAL_TESTIMONIALS);
  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
  const [filterLevel, setFilterLevel] = useState<SchoolLevel | 'all'>('all');
  const [activeMeeting, setActiveMeeting] = useState<Meeting | null>(null);
  const [results, setResults] = useState<ExamResult[]>([]);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [viewingResult, setViewingResult] = useState<ExamResult | null>(null);

  useEffect(() => {
    if (user) {
      setAllUsers(prev => {
        const index = prev.findIndex(u => u.username === user.username);
        if (index === -1) return [...prev, user];
        const newUsers = [...prev];
        newUsers[index] = user;
        return newUsers;
      });
    }
  }, [user]);

  const handleUpdateUser = (updatedUser: User) => {
    setAllUsers(prev => prev.map(u => u.username === updatedUser.username ? updatedUser : u));
    if (user?.username === updatedUser.username) {
      setUser(updatedUser);
    }
  };

  const checkAuth = (nextPage: string) => {
    if (!user) {
      setCurrentPage('login');
      return false;
    }
    if (!user.isAuthorized && user.role !== UserRole.ADMIN) {
       return false;
    }
    return true;
  };

  const handleStartExam = (subject: Subject) => {
    if (checkAuth('exam')) {
      setSelectedSubject(subject);
      setCurrentPage('exam');
    }
  };

  const handleJoinMeeting = (meeting: Meeting) => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    if (!user.isAuthorized && user.role !== UserRole.ADMIN) {
      alert("Verification Pending: Access locked.");
      return;
    }

    if (meeting.id === 'zoom-taofeek') {
      window.open('https://us05web.zoom.us/j/3789657653?pwd=YTRiaCXvUwZSeBv6xj7n65i0OwiBXf.1&omn=81232763063', '_blank');
      return;
    }
    setActiveMeeting(meeting);
    setCurrentPage('classroom');
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
    setActiveMeeting(null);
    setViewingResult(null);
  };

  const filteredSubjects = filterLevel === 'all' 
    ? subjects 
    : subjects.filter(s => s.level === filterLevel);

  const isRestrictedPage = ['virtual', 'results', 'attendance', 'cbt', 'exam', 'tutor'].includes(currentPage);
  const isUnauthorized = user && !user.isAuthorized && user.role !== UserRole.ADMIN;

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Navbar 
        activePage={currentPage} 
        onNavigate={(p) => {
          setCurrentPage(p);
          setSelectedSubject(null);
          setActiveMeeting(null);
          setViewingResult(null);
        }} 
        user={user}
        onLogout={handleLogout}
      />

      <main className="flex-grow">
        {isUnauthorized && isRestrictedPage && (
           <div className="pt-32 pb-20 px-4 text-center max-w-2xl mx-auto">
             <div className="glass-effect p-12 rounded-[3.5rem] shadow-2xl border-4 border-amber-100 bg-white/60">
                <div className="w-24 h-24 bg-amber-100 text-amber-600 rounded-[2rem] flex items-center justify-center text-4xl mb-8 mx-auto shadow-inner font-bold">!</div>
                <h2 className="text-4xl font-black text-slate-900 mb-6 uppercase tracking-tighter">Account Locked</h2>
                <p className="text-slate-600 mb-10 text-lg leading-relaxed">
                   Your registration is successful, but your account is awaiting manual verification from **Christaville Admin (sabatex1979)**.
                </p>
                <button 
                  onClick={() => setCurrentPage('home')}
                  className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-amber-600 transition-all shadow-xl active:scale-95"
                >
                  Return to Homepage
                </button>
             </div>
           </div>
        )}

        {(!isUnauthorized || !isRestrictedPage) && (
          <>
            {currentPage === 'home' && (
              <>
                <Hero 
                  title={config.heroTitle} 
                  subtitle={config.heroSubtitle} 
                  onStart={() => setCurrentPage('cbt')} 
                />
                <HomeSlider slides={slides} />

                {/* Admin Quick Entry Section */}
                {!user && (
                   <section className="py-20 bg-slate-900 overflow-hidden relative">
                     <div className="max-w-4xl mx-auto px-4 text-center">
                        <h2 className="text-3xl font-black text-white mb-6 uppercase tracking-widest">Management Portal</h2>
                        <p className="text-slate-400 mb-10 font-medium">Internal access for verified staff and administrators of Christaville School.</p>
                        <button 
                          onClick={() => setCurrentPage('login')}
                          className="px-12 py-5 bg-white text-slate-900 rounded-[2rem] font-black uppercase tracking-widest hover:bg-amber-500 hover:text-white transition-all shadow-2xl"
                        >
                          Administrator Login
                        </button>
                     </div>
                     <div className="absolute top-0 right-0 p-12 text-white/5 font-black text-9xl pointer-events-none select-none">ADMIN</div>
                   </section>
                )}

                <section className="py-20 bg-white border-y">
                  <div className="max-w-7xl mx-auto px-4 text-center">
                    <h2 className="text-3xl font-black text-slate-900 mb-4 uppercase tracking-tighter">Curriculum Pathways</h2>
                    <p className="text-slate-600 max-w-2xl mx-auto mb-16">Global standards for a local future.</p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                      <div className="group p-12 rounded-[3rem] bg-slate-50 border border-slate-100 text-left hover:bg-slate-900 transition-all duration-500 hover:shadow-2xl">
                        <div className="text-5xl mb-6 group-hover:scale-110 transition-transform">🇬🇧</div>
                        <h3 className="text-2xl font-black text-slate-900 mb-4 group-hover:text-white uppercase tracking-tight">British (Cambridge)</h3>
                        <p className="text-slate-600 group-hover:text-slate-400 leading-relaxed font-medium">Developing critical academic skills and structured knowledge mastery for international success.</p>
                      </div>
                      <div className="group p-12 rounded-[3rem] bg-amber-50 border border-amber-100 text-left hover:bg-amber-600 transition-all duration-500 hover:shadow-2xl">
                        <div className="text-5xl mb-6 group-hover:scale-110 transition-transform">🇺🇸</div>
                        <h3 className="text-2xl font-black text-slate-900 mb-4 group-hover:text-white uppercase tracking-tight">American (Common Core)</h3>
                        <p className="text-amber-800 group-hover:text-amber-100 leading-relaxed font-medium">Holistic development focusing on creativity, continuous assessment, and SAT preparation.</p>
                      </div>
                    </div>
                  </div>
                </section>

                <section className="py-20 bg-slate-50 overflow-hidden">
                   <div className="max-w-7xl mx-auto px-4 text-center">
                      <h2 className="text-3xl font-black text-slate-900 mb-16 uppercase tracking-tighter">Voices of Christaville</h2>
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                        {testimonials.map((t) => (
                          <div key={t.id} className="p-8 bg-white rounded-3xl border border-slate-100 text-left shadow-sm">
                            <div className="flex items-center gap-3 mb-4">
                              <img src={t.avatar} alt={t.name} className="w-10 h-10 rounded-full border-2 border-slate-100" />
                              <div>
                                <h4 className="text-sm font-bold text-slate-900">{t.name}</h4>
                                <p className="text-[10px] text-amber-600 font-bold uppercase">{t.role}</p>
                              </div>
                            </div>
                            <p className="text-xs text-slate-500 leading-relaxed italic">"{t.text}"</p>
                          </div>
                        ))}
                      </div>
                   </div>
                </section>
              </>
            )}

            {(currentPage === 'login' || currentPage === 'register') && !user && (
              <LoginPage 
                initialMode={currentPage === 'register' ? 'register' : 'login'}
                onLogin={(u) => {
                  setUser(u);
                  setCurrentPage(u.role === UserRole.ADMIN ? 'admin' : 'home');
                }} 
              />
            )}

            {currentPage === 'admin' && user?.role === UserRole.ADMIN && (
              <div className="pt-24 pb-20 px-4">
                <AdminDashboard 
                  subjects={subjects} 
                  setSubjects={setSubjects} 
                  config={config} 
                  setConfig={setConfig} 
                  slides={slides}
                  setSlides={setSlides}
                  testimonials={testimonials}
                  setTestimonials={setTestimonials}
                  results={results}
                  setResults={setResults}
                  users={allUsers}
                  onUpdateUser={handleUpdateUser}
                />
              </div>
            )}

            {currentPage === 'virtual' && user?.isAuthorized && (
              <div className="pt-24 pb-20">
                <VirtualClassroom user={user} onJoinMeeting={handleJoinMeeting} />
              </div>
            )}

            {currentPage === 'results' && user?.isAuthorized && (
              <ResultsPage 
                user={user} 
                results={results} 
                onViewResult={(res) => setViewingResult(res)} 
              />
            )}

            {currentPage === 'attendance' && user?.isAuthorized && (
              <AttendancePage 
                user={user} 
                records={attendance} 
                onMarkAttendance={handleMarkAttendance} 
              />
            )}

            {currentPage === 'cbt' && user?.isAuthorized && (
              <div className="pt-24 pb-20 px-4 max-w-7xl mx-auto">
                 <div className="mb-12 text-center">
                  <h2 className="text-5xl font-black text-slate-900 mb-4 tracking-tighter uppercase">Assessment Portal</h2>
                  <p className="text-slate-600 mb-10 text-lg font-medium">Verified student access only.</p>

                  <div className="flex flex-wrap justify-center gap-2">
                    {['all', ...Object.values(SchoolLevel)].map((lvl) => (
                      <button
                        key={lvl}
                        onClick={() => setFilterLevel(lvl as any)}
                        className={`px-8 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                          filterLevel === lvl 
                            ? 'bg-slate-900 text-white shadow-xl scale-105' 
                            : 'bg-white border text-slate-500 hover:bg-slate-50 shadow-sm'
                        }`}
                      >
                        {lvl}
                      </button>
                    ))}
                  </div>
                </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
                  {filteredSubjects.map((sub) => (
                    <div key={sub.id} className="glass-effect p-8 rounded-[2.5rem] border shadow-sm hover:shadow-2xl transition-all flex flex-col group border-white">
                      <div className="text-5xl mb-6 group-hover:scale-125 transition-transform origin-left">{sub.icon}</div>
                      <h3 className="text-xl font-black text-slate-900 mb-1 uppercase tracking-tight">{sub.name}</h3>
                      <span className={`text-[10px] uppercase font-black px-3 py-1 rounded-lg mb-4 inline-block w-fit ${
                        sub.level === SchoolLevel.NURSERY ? 'bg-pink-100 text-pink-700' :
                        sub.level === SchoolLevel.GRADE ? 'bg-blue-100 text-blue-700' :
                        sub.level === SchoolLevel.JUNIOR_SECONDARY ? 'bg-purple-100 text-purple-700' :
                        'bg-green-100 text-green-700'
                      }`}>
                        {sub.level}
                      </span>
                      <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mb-8 mt-auto">{sub.questions.length} Questions Available</p>
                      <button
                        onClick={() => handleStartExam(sub)}
                        className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-amber-600 transition-all shadow-lg text-xs"
                      >
                        Start Exam
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {currentPage === 'exam' && selectedSubject && user?.isAuthorized && (
              <div className="pt-24 pb-20 px-4">
                <CBTEngine 
                  subject={selectedSubject} 
                  user={user}
                  onExit={() => {
                    setCurrentPage('cbt');
                    setSelectedSubject(null);
                  }} 
                  onSaveResult={handleSaveResult}
                />
              </div>
            )}

            {currentPage === 'tutor' && user?.isAuthorized && (
              <div className="pt-24 pb-20 px-4">
                <div className="text-center mb-12">
                  <h2 className="text-4xl font-black text-slate-900 mb-4 tracking-tighter uppercase">AI Learning Assistant</h2>
