                </div>
                <AIAssistant />
              </div>
            )}

            {currentPage === 'about' && (
               <div className="pt-32 pb-20 px-4 max-w-4xl mx-auto text-center">
                <h2 className="text-5xl font-black text-slate-900 mb-10 tracking-tighter uppercase">The Christaville Legacy</h2>
                <div className="glass-effect p-12 rounded-[3.5rem] text-left space-y-8 shadow-2xl border-4 border-white">
                  <p className="text-xl text-slate-600 leading-relaxed font-medium italic">
                    "{config.aboutText}"
                  </p>
                  <div className="h-96 w-full rounded-3xl overflow-hidden shadow-inner bg-slate-200">
                    <img src="https://images.unsplash.com/photo-1509062522246-3755977927d7?auto=format&fit=crop&q=80&w=1200" alt="School" className="w-full h-full object-cover" />
                  </div>
                </div>
              </div>
            )}
          </>
