              </div>
            </div>
          </div>
        )}
      </main>

      {viewingResult && (
        <ResultSlip 
          result={viewingResult} 
          config={config} 
          onClose={() => setViewingResult(null)} 
        />
      )}

      {activeMeeting && user && (
        <VirtualMeetingRoom 
          user={user} 
          meeting={activeMeeting} 
          onExit={() => {
            setActiveMeeting(null);
            setCurrentPage('virtual');
          }} 
        />
      )}

      <Footer />
    </div>
  );
};

export default App;

