import React, { useState } from 'react';
import { Subject, SchoolConfig, ExamResult, User, UserRole, SchoolLevel, Testimonial } from '../types';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  config: SchoolConfig;
  setConfig: React.Dispatch<React.SetStateAction<SchoolConfig>>;
  slides: any[];
  setSlides: React.Dispatch<React.SetStateAction<any[]>>;
  testimonials: Testimonial[];
  setTestimonials: React.Dispatch<React.SetStateAction<Testimonial[]>>;
  results: ExamResult[];
  setResults: React.Dispatch<React.SetStateAction<ExamResult[]>>;
  users: User[];
  onUpdateUser: (updatedUser: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  subjects, 
  setSubjects, 
  config, 
  setConfig, 
  slides,
  setSlides,
  testimonials,
  setTestimonials,
  results, 
  setResults, 
  users, 
  onUpdateUser 
}) => {
  const [activeTab, setActiveTab] = useState<'results' | 'cbt' | 'content'>('results');
  const [contentSubTab, setContentSubTab] = useState<'global' | 'slider' | 'testimonials'>('global');
  const [editingResult, setEditingResult] = useState<ExamResult | null>(null);
  const [editingSubject, setEditingSubject] = useState<Subject | null>(null);

  const handleConfigChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setConfig(prev => ({ ...prev, [name]: value }));
  };

  // Slider Management
  const handleSlideChange = (id: number, field: string, value: string) => {
    setSlides(prev => prev.map(s => s.id === id ? { ...s, [field]: value } : s));
  };

  // Testimonial Management
  const handleTestimonialChange = (id: string, field: string, value: string) => {
    setTestimonials(prev => prev.map(t => t.id === id ? { ...t, [field]: value } : t));
  };

  const getGrade = (percentage: number) => {
    if (percentage >= 70) return 'A';
    if (percentage >= 60) return 'B';
    if (percentage >= 50) return 'C';
    if (percentage >= 40) return 'D';
    return 'F';
  };

  const handleUpdateSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingSubject) return;
    setSubjects(subjects.map(s => s.id === editingSubject.id ? editingSubject : s));
    setEditingSubject(null);
  };

  const handleUpdateResult = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingResult) return;
    const percentage = Math.round((editingResult.score / editingResult.totalQuestions) * 100);
    const updated = {
      ...editingResult,
      percentage,
      grade: getGrade(percentage)
    };
    setResults(results.map(r => r.id === updated.id ? updated : r));
    setEditingResult(null);
  };

  const generateNewPin = () => {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let pin = 'CV-';
    for (let i = 0; i < 4; i++) {
      pin += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    if (editingResult) {
      setEditingResult({...editingResult, pin});
    }
  };

  const authorizedUsers = users.filter(u => u.isAuthorized && u.role !== UserRole.ADMIN);

  return (
    <div className="max-w-6xl mx-auto p-4 print:hidden">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Christaville Management Hub</h2>
          <p className="text-slate-600 font-medium">System Administrator: <span className="text-amber-600 font-bold">sabatex1979</span></p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl w-full md:w-auto overflow-x-auto shadow-inner">
          {[
            { id: 'results', label: 'Exam Results' },
            { id: 'cbt', label: 'CBT Portal' },
            { id: 'content', label: 'Global Editor' }
          ].map((tab) => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`whitespace-nowrap px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === tab.id ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'results' && (
        <div className="space-y-6 animate-in fade-in duration-500">
           <div className="glass-effect p-8 rounded-[2rem] border shadow-sm border-white">
              <h3 className="text-xl font-bold mb-6">Manage All Student Results</h3>
              <div className="overflow-x-auto">
                 <table className="w-full text-left">
