/**
 * Procedurally generates realistic questions tailored to the school level and subject topics.
 */
const generateAcademicQuestions = (subjectName: string, level: SchoolLevel, count: number = 20): Question[] => {
  const result: Question[] = [];

  const topicPool: Record<string, Record<string, string[]>> = {
    [SchoolLevel.NURSERY]: {
      'Literacy': ['letter A', 'the sound /b/', 'capital letters', 'rhyming words', 'letter tracing'],
      'Numbers & Shapes': ['counting 1-5', 'circles', 'squares', 'counting 1-10', 'triangles'],
      'Social Habits': ['greeting elders', 'saying please', 'sharing toys', 'obeying rules', 'cleaning up'],
      'Health Habits': ['washing hands', 'brushing teeth', 'eating fruits', 'taking a bath', 'cutting nails'],
      'Nature Study': ['domestic animals', 'colorful flowers', 'the sun', 'the rain', 'green trees'],
      'Creative Arts': ['coloring', 'drawing circles', 'finger painting', 'modeling clay', 'pasting'],
      'Rhymes': ['Twinkle Twinkle', 'Baa Baa Black Sheep', 'Row Your Boat', 'Humpty Dumpty', 'Old Macdonald'],
      'Handwriting': ['tracing lines', 'tracing curves', 'forming letter O', 'forming letter I', 'forming letter L'],
      'Religious Studies': ['God the creator', 'The Bible/Quran', 'Praying', 'Kindness', 'Love for parents'],
      'Physical Education': ['running', 'jumping', 'throwing balls', 'marching', 'stretching']
    },
    [SchoolLevel.GRADE]: {
      'Mathematics': ['addition of 2-digit numbers', 'multiplication tables', 'place value', 'simple fractions', 'word problems'],
      'English Studies': ['nouns and verbs', 'adjectives', 'synonyms', 'punctuation', 'sentence structure'],
      'Basic Science': ['parts of a plant', 'living and non-living things', 'the five senses', 'types of soil', 'sources of light'],
      'Social Studies': ['the family', 'our community', 'national symbols', 'transportation', 'culture'],
      'Information Tech': ['parts of a computer', 'using the mouse', 'typing keys', 'software basics', 'the monitor'],
      'Home Economics': ['personal hygiene', 'kitchen utensils', 'care of the home', 'sewing tools', 'types of food'],
      'Agric Science': ['types of crops', 'farm animals', 'simple farm tools', 'uses of water', 'weed control'],
      'Creative Arts': ['primary colors', 'paper craft', 'local songs', 'drama basics', 'sculpture'],
      'Civic Education': ['rights of a child', 'national identity', 'good citizenship', 'constituted authority', 'values'],
      'Verbal Reasoning': ['word analogies', 'letter series', 'alphabetical order', 'forming words', 'logical patterns'],
      'Quantitative Reasoning': ['number series', 'mathematical puzzles', 'logic blocks', 'pattern matching', 'basic arithmetic']
    },
    [SchoolLevel.JUNIOR_SECONDARY]: {
      'Mathematics': ['algebraic expressions', 'plane geometry', 'statistics and probability', 'ratio and proportion', 'indices'],
      'English Language': ['tenses', 'figures of speech', 'essay writing', 'comprehension strategies', 'active and passive voice'],
      'Basic Science': ['matter and energy', 'reproduction in plants', 'respiratory system', 'forces', 'chemical symbols'],
      'Basic Tech': ['drawing instruments', 'safety rules', 'woodwork basics', 'metalwork tools', 'gears and pulleys'],
      'Business Studies': ['office equipment', 'bookkeeping', 'commerce basics', 'insurance', 'consumer rights'],
      'Social Studies': ['human rights', 'national consciousness', 'social issues', 'governance', 'globalization'],
      'Civic Education': ['democracy', 'national values', 'the constitution', 'rule of law', 'integrity'],
      'Computer Science': ['binary numbers', 'operating systems', 'internet protocols', 'logic gates', 'computer ethics'],
      'Agric Science': ['farm power', 'animal nutrition', 'crop production', 'forestry', 'soil fertility'],
      'Home Economics': ['food nutrients', 'clothing construction', 'home management', 'entrepreneurship', 'consumer education']
    }
  };

  const levelTopics = topicPool[level] || {};
  const currentTopics = levelTopics[subjectName] || ['General knowledge', 'Core concepts', 'Practical application'];

  for (let i = 1; i <= count; i++) {
    const topic = currentTopics[i % currentTopics.length];
    const isNursery = level === SchoolLevel.NURSERY;

    result.push({
      id: `${level.toLowerCase().replace(/\s/g, '-')}-${subjectName.toLowerCase().replace(/\s/g, '-')}-${i}`,
      text: isNursery 
        ? `Can you pick the correct ${topic}?`
        : `Which of the following best describes the function of ${topic}?`,
      options: [
        `Option A: ${topic} related concept`,
        `Option B: Another ${topic} part`,
        `Option C: A different ${topic} view`,
        `Option D: None of the above ${topic}`
      ],
      correctAnswer: (i * 7) % 4
    });
  }
  return result;
};

