                {['all', ...Object.values(SchoolLevel)].map((lvl) => (
                  <button key={lvl} onClick={() => setFilterLevel(lvl as any)} className={`px-8 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${filterLevel === lvl ? 'bg-slate-900 text-white shadow-xl scale-105' : 'bg-white border text-slate-500 hover:bg-slate-50 shadow-sm'}`}>
                    {lvl}
                  </button>
                ))}
              </div>
            </div>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {filteredSubjects.map((sub) => (
                <div key={sub.id} className="glass-effect p-8 rounded-[2.5rem] border shadow-sm hover:shadow-2xl transition-all flex flex-col group border-white">
                  <div className="text-5xl mb-6 group-hover:scale-125 transition-transform origin-left">{sub.icon}</div>
