import React, { useState, useEffect } from 'react';
import { Subject, ExamResult, User } from '../types';

interface CBTEngineProps {
  subject: Subject;
  user: User;
  onExit: () => void;
  onSaveResult: (result: ExamResult) => void;
}

const CBTEngine: React.FC<CBTEngineProps> = ({ subject, user, onExit, onSaveResult }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [timeLeft, setTimeLeft] = useState(3600); // 60 minutes
  const [isFinished, setIsFinished] = useState(false);
  const [isSaved, setIsSaved] = useState(false);

  useEffect(() => {
    if (timeLeft <= 0) {
      setIsFinished(true);
      return;
    }
    const timer = setInterval(() => setTimeLeft((prev) => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft]);

  const currentQuestion = subject.questions[currentIndex];

  const handleSelectOption = (optionIndex: number) => {
    setAnswers({ ...answers, [currentQuestion.id]: optionIndex });
  };

  const calculateScore = () => {
    let score = 0;
    subject.questions.forEach((q) => {
      if (answers[q.id] === q.correctAnswer) {
        score++;
      }
    });
    return score;
  };

  const getGrade = (percentage: number) => {
    if (percentage >= 70) return 'A';
    if (percentage >= 60) return 'B';
    if (percentage >= 50) return 'C';
    if (percentage >= 40) return 'D';
    return 'F';
  };

  const handleFinish = () => {
    setIsFinished(true);
  };

  const generateAutoPin = () => {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let pin = 'CV-';
    for (let i = 0; i < 4; i++) {
      pin += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return pin;
  };

  const handleOfficialSave = () => {
    const score = calculateScore();
    const percentage = Math.round((score / subject.questions.length) * 100);
    const result: ExamResult = {
      id: Date.now().toString(),
      studentName: user.fullName,
      studentClass: user.studentClass || 'N/A',
      subjectName: subject.name,
      subjectLevel: subject.level,
      score,
      totalQuestions: subject.questions.length,
      percentage,
      grade: getGrade(percentage),
      date: new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }),
      pin: generateAutoPin()
    };
    onSaveResult(result);
    setIsSaved(true);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (isFinished) {
    const score = calculateScore();
    const percentage = Math.round((score / subject.questions.length) * 100);
    const grade = getGrade(percentage);

    return (
      <div className="max-w-2xl mx-auto p-16 glass-effect rounded-[4rem] shadow-2xl text-center border-[10px] border-white animate-in zoom-in-95 duration-500">
        <div className="w-32 h-32 bg-slate-900 rounded-[2.5rem] flex items-center justify-center text-white text-6xl font-black mx-auto mb-8 shadow-2xl border-8 border-slate-800 animate-bounce">
           {grade}
        </div>
        <h2 className="text-4xl font-black text-slate-900 mb-4 tracking-tighter uppercase">Assessment Complete!</h2>
        <div className="inline-block px-10 py-3 bg-amber-500 text-slate-900 rounded-full font-black text-sm mb-10 uppercase tracking-[0.3em] shadow-lg">
           FINAL GRADE: {grade} ({percentage}%)
        </div>

        <p className="text-xl text-slate-600 mb-12 leading-relaxed font-medium">
          Brilliant effort, {user.fullName}! You've completed the {subject.name} exam.
        </p>

        <div className="space-y-6">
          {!isSaved ? (
            <button
              onClick={handleOfficialSave}
              className="w-full py-6 bg-slate-900 text-white rounded-[2.5rem] font-black uppercase tracking-widest hover:bg-green-600 shadow-2xl flex items-center justify-center gap-4 transition-all"
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" />
              </svg>
              Save to Official Results
            </button>
          ) : (
            <div className="w-full py-6 bg-green-50 text-green-700 border-4 border-green-100 rounded-[2.5rem] font-black uppercase tracking-widest flex items-center justify-center gap-4 mb-6">
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
              </svg>
              Saved Officially
            </div>
          )}

          <div className="grid grid-cols-2 gap-6">
            <button
              onClick={() => {
                  setCurrentIndex(0);
                  setAnswers({});
                  setTimeLeft(3600);
                  setIsFinished(false);
                  setIsSaved(false);
              }}
              className="py-5 border-4 border-slate-100 text-slate-900 rounded-[2rem] font-black uppercase tracking-widest hover:bg-slate-50 transition-all text-xs"
            >
              Practice Again
            </button>
            <button
              onClick={onExit}
              className="py-5 bg-amber-600 text-white rounded-[2rem] font-black uppercase tracking-widest hover:bg-amber-700 shadow-xl transition-all text-xs"
            >
              Exit Portal
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto px-4">
      <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
        <div className="text-center md:text-left">
          <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase mb-1">{subject.name}</h2>
          <div className="flex items-center gap-3">
            <span className="px-4 py-1 bg-amber-500 text-slate-900 rounded-lg text-[10px] font-black uppercase tracking-widest">Live Exam</span>
            <span className="text-slate-400 font-bold text-xs uppercase tracking-widest">{subject.level} OFFICIAL ASSESSMENT</span>
          </div>
        </div>
        <div className="px-10 py-5 bg-slate-900 text-amber-500 rounded-[2rem] font-mono font-black text-3xl shadow-2xl border-4 border-slate-800 tracking-tighter">
          {formatTime(timeLeft)}
        </div>
      </div>

      <div className="mb-12 flex gap-1.5 h-3">
        {subject.questions.map((_, i) => (
          <div
            key={i}
            className={`flex-1 rounded-full transition-all duration-500 ${
              i === currentIndex ? 'bg-amber-500 scale-y-150' : answers[subject.questions[i].id] !== undefined ? 'bg-slate-900' : 'bg-slate-200'
            }`}
          />
        ))}
      </div>

      <div className="glass-effect rounded-[3.5rem] p-12 md:p-20 shadow-2xl border-4 border-white mb-12 min-h-[500px] relative overflow-hidden backdrop-blur-3xl">
        <div className="absolute top-0 right-0 p-16 opacity-[0.03] pointer-events-none select-none">
          <div className="text-[200px] font-black">{currentIndex + 1}</div>
        </div>

        <div className="flex items-center gap-4 mb-8">
            <span className="w-16 h-16 bg-slate-900 text-white rounded-2xl flex items-center justify-center text-2xl font-black">{currentIndex + 1}</span>
            <span className="inline-block px-5 py-2 bg-slate-900/5 text-slate-900 rounded-full font-black text-xs uppercase tracking-[0.2em]">
              Question {currentIndex + 1} of {subject.questions.length}
            </span>
        </div>

        <h3 className="text-3xl md:text-4xl font-black text-slate-900 mb-12 leading-tight relative z-10">{currentQuestion.text}</h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
          {currentQuestion.options.map((option, idx) => (
            <button
              key={idx}
              onClick={() => handleSelectOption(idx)}
              className={`w-full text-left px-8 py-7 rounded-[2.5rem] border-4 transition-all group flex items-center relative overflow-hidden ${
                answers[currentQuestion.id] === idx
                  ? 'border-amber-500 bg-slate-900 text-white shadow-2xl scale-[1.02]'
                  : 'border-white bg-white/40 hover:border-amber-200 text-slate-700 hover:scale-[1.01]'
              }`}
            >
              <span className={`w-14 h-14 rounded-2xl flex items-center justify-center mr-6 font-black text-xl transition-all ${
                answers[currentQuestion.id] === idx 
                  ? 'bg-amber-500 text-slate-900' 
                  : 'bg-slate-100 text-slate-400 group-hover:bg-amber-50'
              }`}>
                {String.fromCharCode(65 + idx)}
              </span>
              <span className="text-xl font-bold">{option}</span>
            </button>
          ))}
        </div>
      </div>

      <div className="flex justify-between items-center gap-6">
        <button
          disabled={currentIndex === 0}
          onClick={() => setCurrentIndex(currentIndex - 1)}
          className="px-10 py-5 border-4 border-white text-slate-900 rounded-[2rem] font-black uppercase text-xs tracking-widest disabled:opacity-30 hover:bg-white transition-all shadow-lg"
        >
          Previous
        </button>

        <div className="hidden md:block flex-1 text-center text-slate-400 font-black text-xs uppercase tracking-[0.5em]">
          Portal Session ID: CHR-{subject.id.toUpperCase()}
        </div>

        {currentIndex === subject.questions.length - 1 ? (
          <button
            onClick={handleFinish}
            className="px-16 py-5 bg-green-600 text-white rounded-[2rem] font-black uppercase text-xs tracking-widest hover:bg-green-700 shadow-2xl transition-all animate-pulse"
          >
            Final Submission
          </button>
        ) : (
          <button
            onClick={() => setCurrentIndex(currentIndex + 1)}
            className="px-16 py-5 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-xs tracking-widest hover:bg-amber-600 shadow-2xl transition-all"
          >
            Next Question
          </button>
        )}
      </div>
    </div>
  );
};

