const generateMaterials = (subjectName: string): LearningMaterial[] => [
  { id: `m1-${subjectName}`, title: `Introduction to ${subjectName}`, type: 'Note', content: `This note covers the fundamental basics of ${subjectName}. Students should read chapters 1-3.` },
  { id: `m2-${subjectName}`, title: `Mastery Video: ${subjectName}`, type: 'Video', content: 'A 15-minute comprehensive video guide.', url: 'https://vimeo.com' },
  { id: `m3-${subjectName}`, title: `Revision PDF: ${subjectName}`, type: 'PDF', content: 'Summary of the entire term curriculum.', url: '#' },
];

const generateTaskQuestions = (subjectName: string, type: TaskType, count: number = 10): Question[] => {
  const q: Question[] = [];
  for (let i = 1; i <= count; i++) {
    q.push({
      id: `${subjectName}-${type}-${i}`,
      text: `${type} Question ${i}: Related to ${subjectName} core concepts.`,
      options: ['Option A: Correct Approach', 'Option B: Common Misconception', 'Option C: Theoretical View', 'Option D: Practical Application'],
      correctAnswer: 0,
      taskType: type
    });
  }
  return q;
};

const generateAcademicQuestions = (subjectName: string, level: SchoolLevel, count: number = 50): Question[] => {
  const result: Question[] = [];
  for (let i = 1; i <= count; i++) {
    result.push({
      id: `${level}-${subjectName}-Exam-${i}`,
      text: `Official Exam Question ${i} for ${subjectName}.`,
      options: ['Choice 1', 'Choice 2', 'Choice 3', 'Choice 4'],
      correctAnswer: (i % 4),
      taskType: TaskType.EXAM
    });
  }
  return result;
};

