                </div>
              )}
            </div>
          </div>
        )}

        {currentPage === 'classroom' && activeMeeting && user && (
          <VirtualMeetingRoom user={user} meeting={activeMeeting} onExit={() => {setActiveMeeting(null); setCurrentPage('virtual');}} />
        )}

        {currentPage === 'exam-portal' && selectedSubject && user && (
           <div className="pt-24 pb-20 px-4">
             <CBTEngine 
                subject={selectedSubject} 
                user={user} 
                taskType={activeTaskType}
                onExit={() => setCurrentPage(activeTaskType === TaskType.EXAM ? 'cbt' : 'homework')} 
                onSaveResult={(r) => setResults(prev => [r, ...prev])} 
              />
           </div>
        )}

        {currentPage === 'results' && user && <ResultsPage user={user} results={results} onViewResult={(res) => setViewingResult(res)} />}
        {currentPage === 'attendance' && user && <AttendancePage user={user} records={attendance} onMarkAttendance={(recs) => setAttendance(prev => [...recs, ...prev])} />}
        {currentPage === 'tutor' && user && <div className="pt-24 pb-20 px-4"><AIAssistant /></div>}
        {currentPage === 'login' && !user && <LoginPage onLogin={handleLogin} />}
        {currentPage === 'register' && !user && <LoginPage initialMode="register" onLogin={handleLogin} />}
        {currentPage === 'contact' && <div className="pt-24 pb-20"><ContactUs config={config} /></div>}

        {currentPage === 'about' && (
          <div className="pt-32 pb-20 px-4 max-w-5xl mx-auto">
            <h2 className="text-6xl font-black text-slate-900 mb-12 uppercase tracking-tighter">The Christaville Legacy</h2>
            <div className="glass-effect p-16 rounded-[4rem] text-left space-y-10 shadow-2xl border-[10px] border-white/50">
              <p className="text-2xl text-slate-700 leading-relaxed font-medium italic">"{config.aboutText}"</p>
              <div className="h-[30rem] w-full rounded-[3rem] overflow-hidden shadow-2xl border-4 border-white relative group">
                <img src="https://images.unsplash.com/photo-1523050853063-bd80e27433fb?auto=format&fit=crop&q=80&w=1200" alt="Graduation" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000" />
                <div className="absolute inset-0 bg-gradient-to-t from-slate-900/40 to-transparent"></div>
              </div>
            </div>
          </div>
        )}

        {currentPage === 'admin' && user?.role === UserRole.ADMIN && (
          <div className="pt-24 pb-20 px-4">
            <AdminDashboard 
              subjects={subjects} 
              setSubjects={setSubjects} 
              config={config} 
              setConfig={setConfig} 
              slides={slides}
              setSlides={setSlides}
              testimonials={testimonials}
              setTestimonials={setTestimonials}
              results={results}
              setResults={setResults}
              users={allUsers}
              meetings={meetings}
              setMeetings={setMeetings}
              onUpdateUser={(u) => setAllUsers(prev => prev.map(usr => usr.username === u.username ? u : usr))} 
            />
          </div>
        )}
      </main>

      {viewingResult && <ResultSlip result={viewingResult} config={config} onClose={() => setViewingResult(null)} />}
      <Footer config={config} />
    </div>
  );
};

export default App;

import { SchoolLevel, Subject, Question, SchoolConfig, Testimonial, Meeting, TaskType, LearningMaterial, LibraryResource } from './types';

const generateMaterials = (subjectName: string, topics: string[]): LearningMaterial[] => {
  return topics.map((topic, index) => ({
    id: `m-${subjectName}-${index}`,
    title: topic,
    type: index % 3 === 0 ? 'Note' : index % 3 === 1 ? 'Video' : 'PDF',
    content: `Comprehensive study guide for ${topic} in ${subjectName}. This module covers the core objectives, definitions, and practical examples required for term mastery.`,
    url: index % 3 === 1 ? 'https://vimeo.com/705816503' : '#'
  }));
};

const generateTaskQuestions = (subjectName: string, type: TaskType, count: number = 10): Question[] => {
  const q: Question[] = [];
  for (let i = 1; i <= count; i++) {
    q.push({
      id: `${subjectName}-${type}-${i}`,
      text: `${type} Question ${i}: Which of the following best describes the fundamental principle of ${subjectName} discussed in week ${i % 5 + 1}?`,
      options: ['The Absolute Theory', 'The Practical Framework', 'The Analytical Approach', 'The Systematic Method'],
      correctAnswer: i % 4,
      taskType: type
    });
  }
  return q;
};

const generateAcademicQuestions = (subjectName: string, level: SchoolLevel, count: number = 20): Question[] => {
  const result: Question[] = [];
  for (let i = 1; i <= count; i++) {
    result.push({
      id: `${level}-${subjectName}-Exam-${i}`,
      text: `Official Exam Question ${i} for ${subjectName}. Identify the primary objective of the lesson on ${subjectName} covered during the mid-term session.`,
      options: ['Option Alpha', 'Option Beta', 'Option Gamma', 'Option Delta'],
      correctAnswer: (i % 4),
      taskType: TaskType.EXAM
    });
  }
  return result;
};

